//! Fixture replay for the collection-truth beta packet.
//!
//! Fixtures live under `fixtures/ux/m3/collection_truth/` and are
//! generated by the `aureline_shell_collection_truth` headless inspector.

use aureline_shell::collection_truth::{
    seeded_collection_truth_beta_packet, validate_collection_truth_beta_packet,
    BatchReviewSheetRecord, CollectionScopeCounterRecord, CollectionTruthBetaPacket,
    CollectionTruthSurfaceFamily, FilterBarStateRecord, SavedCollectionViewRecord,
    SavedViewDriftState, SavedViewFallbackBehavior, ScopeCounterClass, SelectAllEscalationClass,
    COLLECTION_TRUTH_BETA_SCHEMA_VERSION, COLLECTION_TRUTH_BETA_SHARED_CONTRACT_REF,
};

const FIXTURE_DIR: &str = concat!(
    env!("CARGO_MANIFEST_DIR"),
    "/../../fixtures/ux/m3/collection_truth"
);

fn load<T: serde::de::DeserializeOwned>(path: &str) -> T {
    let body =
        std::fs::read_to_string(path).unwrap_or_else(|err| panic!("failed to read {path}: {err}"));
    serde_json::from_str(&body).unwrap_or_else(|err| panic!("failed to parse {path}: {err}"))
}

#[test]
fn fixture_packet_matches_seeded_builder() {
    let on_disk: CollectionTruthBetaPacket = load(&format!("{FIXTURE_DIR}/packet.json"));
    let live = seeded_collection_truth_beta_packet();
    assert_eq!(
        on_disk, live,
        "fixture packet must match the seeded collection-truth packet"
    );
    assert_eq!(
        on_disk.shared_contract_ref,
        COLLECTION_TRUTH_BETA_SHARED_CONTRACT_REF
    );
    assert_eq!(on_disk.schema_version, COLLECTION_TRUTH_BETA_SCHEMA_VERSION);
    validate_collection_truth_beta_packet(&on_disk).expect("packet must validate");
}

#[test]
fn per_surface_fixture_files_round_trip_through_shared_types() {
    let packet: CollectionTruthBetaPacket = load(&format!("{FIXTURE_DIR}/packet.json"));
    for case in &packet.cases {
        let dir = format!("{FIXTURE_DIR}/{}", case.surface_family.as_str());
        let filter_bar: FilterBarStateRecord = load(&format!("{dir}/filter_bar.json"));
        let saved_view: SavedCollectionViewRecord = load(&format!("{dir}/saved_view.json"));
        let scope_counter: CollectionScopeCounterRecord =
            load(&format!("{dir}/scope_counter.json"));
        let batch_review: BatchReviewSheetRecord = load(&format!("{dir}/batch_review.json"));

        assert_eq!(filter_bar, case.filter_bar);
        assert_eq!(saved_view, case.saved_view);
        assert_eq!(scope_counter, case.scope_counter);
        assert_eq!(batch_review, case.batch_review);
    }
}

#[test]
fn fixtures_cover_every_surface_family() {
    let packet: CollectionTruthBetaPacket = load(&format!("{FIXTURE_DIR}/packet.json"));
    for required in CollectionTruthSurfaceFamily::all() {
        assert!(
            packet
                .cases
                .iter()
                .any(|case| case.surface_family == required),
            "missing fixture surface family {}",
            required.as_str()
        );
    }
}

#[test]
fn fixtures_exercise_visible_or_loaded_and_all_matching_select_all() {
    let packet: CollectionTruthBetaPacket = load(&format!("{FIXTURE_DIR}/packet.json"));
    let mut saw_visible_or_loaded = false;
    let mut saw_all_matching_safe = false;
    for case in &packet.cases {
        match case.batch_review.select_all_escalation_class {
            SelectAllEscalationClass::VisibleOrLoaded => saw_visible_or_loaded = true,
            SelectAllEscalationClass::AllMatchingSafe => saw_all_matching_safe = true,
            SelectAllEscalationClass::AllMatchingRefused => {}
        }
    }
    assert!(
        saw_visible_or_loaded,
        "at least one fixture must default to visible_or_loaded select-all"
    );
    assert!(
        saw_all_matching_safe,
        "at least one fixture must safely escalate to all_matching"
    );
}

#[test]
fn fixtures_expose_provider_limit_and_partial_data_chips() {
    let packet: CollectionTruthBetaPacket = load(&format!("{FIXTURE_DIR}/packet.json"));
    let mut saw_provider_limit = false;
    let mut saw_partial_data = false;
    let mut saw_policy = false;
    let mut saw_workset = false;
    let mut saw_client_limit = false;
    for case in &packet.cases {
        for chip in &case.filter_bar.chips {
            use aureline_shell::collection_truth::NarrowingSourceClass;
            match chip.source_class {
                NarrowingSourceClass::ProviderLimit => saw_provider_limit = true,
                NarrowingSourceClass::PartialData => saw_partial_data = true,
                NarrowingSourceClass::Policy => saw_policy = true,
                NarrowingSourceClass::Workset => saw_workset = true,
                NarrowingSourceClass::ClientLimit => saw_client_limit = true,
                _ => {}
            }
        }
    }
    assert!(
        saw_provider_limit,
        "fixtures must expose provider_limit chips"
    );
    assert!(saw_partial_data, "fixtures must expose partial_data chips");
    assert!(saw_policy, "fixtures must expose policy chips");
    assert!(saw_workset, "fixtures must expose workset chips");
    assert!(saw_client_limit, "fixtures must expose client_limit chips");
}

#[test]
fn fixtures_expose_all_required_counter_classes() {
    let packet: CollectionTruthBetaPacket = load(&format!("{FIXTURE_DIR}/packet.json"));
    let mut classes = std::collections::BTreeSet::new();
    for case in &packet.cases {
        for row in &case.scope_counter.rows {
            classes.insert(row.counter_class);
        }
    }
    for required in [
        ScopeCounterClass::Visible,
        ScopeCounterClass::Loaded,
        ScopeCounterClass::Matching,
        ScopeCounterClass::Total,
        ScopeCounterClass::Partial,
        ScopeCounterClass::ProviderOwned,
    ] {
        assert!(
            classes.contains(&required),
            "fixtures must cover counter class {}",
            required.as_str()
        );
    }
}

#[test]
fn fixtures_exercise_saved_view_drift_states() {
    let packet: CollectionTruthBetaPacket = load(&format!("{FIXTURE_DIR}/packet.json"));
    let mut drifts = std::collections::BTreeSet::new();
    let mut fallbacks = std::collections::BTreeSet::new();
    for case in &packet.cases {
        drifts.insert(case.saved_view.drift_state);
        fallbacks.insert(case.saved_view.fallback_behavior);
    }
    assert!(drifts.contains(&SavedViewDriftState::BoundCurrentStateMatchesCaptured));
    assert!(drifts.contains(&SavedViewDriftState::ProviderStateDriftedDisclosed));
    assert!(drifts.contains(&SavedViewDriftState::ColumnSetDriftedDisclosed));
    assert!(drifts.contains(&SavedViewDriftState::PolicyNarrowingChangedDisclosed));
    assert!(fallbacks.contains(&SavedViewFallbackBehavior::PreserveAndLabelDegraded));
    assert!(fallbacks.contains(&SavedViewFallbackBehavior::LoadPortableSubsetWithLabels));
    assert!(fallbacks.contains(&SavedViewFallbackBehavior::RefuseUntilRebound));
}
